def CalcWindwardFlag(WindDir: Real64, SurfAzimuth: Real64) -> Real64:
    var Diff = mod(abs(WindDir - SurfAzimuth), 360.0)
    if Diff > 180.0:
        Diff = 360.0 - Diff
    var Windward = sign(1.0, 100.0 - Diff)
    return Windward * (1.0 - Diff / 180.0)

