def CalcTiltBranchConvection(DeltaTemp: Real64, CosTilt: Real64) -> Real64:
    var Hc: Real64
    if CosTilt > 0.5:
        Hc = 9.482 * (abs(DeltaTemp) ** (1.0/3.0)) / (7.283 - abs(CosTilt))
    elif CosTilt < -0.5:
        Hc = 1.810 * (abs(DeltaTemp) ** (1.0/3.0)) / (1.382 + abs(CosTilt))
    else:
        Hc = 1.31 * (abs(DeltaTemp) ** (1.0/3.0))
    return Hc

